customCss:
/* MF-QA-FIX-v1 */
.mfp.mfp-wellness-patient-intake{--mf-primary:#0f9d76;--mf-accent:#0f9d76;--mf-primary-hover:#0c7d5e;--mf-primary-light:#e0f5ee;--primary:#0f9d76;}
/* END-MF-QA-FIX */
/* ============================================================
   MegaForm Premium Template — Wellness & Patient Intake
   Scope: .mfp.mfp-wellness-patient-intake
   Design profile: Soft mint-white shell, emerald accent,
   centered single column, top dot-progress stepper,
   pill-shaped inputs. All colours use --mf-* variables;
   hard-coded values are fallbacks only. No !important.
   ============================================================ */

/* ---------- Reset ---------- */
.mfp.mfp-wellness-patient-intake *,
.mfp.mfp-wellness-patient-intake *::before,
.mfp.mfp-wellness-patient-intake *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

/* ---------- Root wrapper ---------- */
.mfp.mfp-wellness-patient-intake {
  font-family: inherit;
  color: var(--mf-text, #17352b);
  background: var(--mf-bg, #f4faf7);
  border-radius: var(--mf-radius, 24px);
  max-width: 720px;
  width: 100%;
  margin: 0 auto;
  padding: 40px 36px 32px;
  box-shadow: var(--mf-shadow, 0 20px 60px rgba(15, 157, 118, 0.12));
  border: 1px solid var(--mf-border, rgba(15, 157, 118, 0.12));
}

/* ============================================================
   HEADER
   ============================================================ */
.mfp.mfp-wellness-patient-intake .mfp-header {
  text-align: center;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 10px;
  margin-bottom: 28px;
}
.mfp.mfp-wellness-patient-intake .mfp-brand {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 6px 14px 6px 8px;
  border-radius: 999px;
  background: var(--mf-accent-soft, rgba(15, 157, 118, 0.10));
}
.mfp.mfp-wellness-patient-intake .mfp-brand-mark {
  width: 18px;
  height: 18px;
  border-radius: 50%;
  background: var(--mf-accent, #0f9d76);
  box-shadow: 0 0 0 4px var(--mf-accent-soft, rgba(15, 157, 118, 0.15));
}
.mfp.mfp-wellness-patient-intake .mfp-brand-label {
  font-size: 13px;
  font-weight: 700;
  letter-spacing: 0.02em;
  color: var(--mf-accent-strong, #0b7d5e);
}
.mfp.mfp-wellness-patient-intake .mfp-form-title {
  font-size: 28px;
  font-weight: 700;
  letter-spacing: -0.02em;
  color: var(--mf-text, #17352b);
}
.mfp.mfp-wellness-patient-intake .mfp-form-subtitle {
  font-size: 15px;
  line-height: 1.5;
  color: var(--mf-muted, #5c7a70);
  max-width: 46ch;
}

/* ============================================================
   DOT STEPPER
   ============================================================ */
.mfp.mfp-wellness-patient-intake .mfp-stepper {
  position: relative;
  margin: 0 auto 32px;
  max-width: 480px;
}
.mfp.mfp-wellness-patient-intake .mfp-stepper-list {
  list-style: none;
  display: flex;
  justify-content: space-between;
  position: relative;
  z-index: 1;
}
.mfp.mfp-wellness-patient-intake .mfp-stepper-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
  flex: 1;
}
.mfp.mfp-wellness-patient-intake .mfp-step-dot {
  width: 36px;
  height: 36px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--mf-surface, #ffffff);
  border: 2px solid var(--mf-border, rgba(15, 157, 118, 0.20));
  color: var(--mf-muted, #5c7a70);
  font-size: 14px;
  font-weight: 700;
  transition: all 0.25s ease;
}
.mfp.mfp-wellness-patient-intake .mfp-step-label {
  font-size: 12px;
  font-weight: 600;
  color: var(--mf-muted, #5c7a70);
  transition: color 0.25s ease;
}
/* Connecting track behind dots */
.mfp.mfp-wellness-patient-intake .mfp-progress {
  position: absolute;
  top: 18px;
  left: 18px;
  right: 18px;
  height: 3px;
  border-radius: 999px;
  background: var(--mf-border, rgba(15, 157, 118, 0.18));
  z-index: 0;
}
.mfp.mfp-wellness-patient-intake .mfp-progress-fill {
  display: block;
  height: 100%;
  width: 0%;
  border-radius: 999px;
  background: var(--mf-accent, #0f9d76);
  transition: width 0.35s ease;
}
/* Active + completed states (driven by MegaForm data-active attribute) */
.mfp.mfp-wellness-patient-intake .mfp-stepper-item[data-state="active"] .mfp-step-dot,
.mfp.mfp-wellness-patient-intake .mfp-stepper-item[data-state="complete"] .mfp-step-dot {
  background: var(--mf-accent, #0f9d76);
  border-color: var(--mf-accent, #0f9d76);
  color: var(--mf-on-accent, #ffffff);
}
.mfp.mfp-wellness-patient-intake .mfp-stepper-item[data-state="active"] .mfp-step-label,
.mfp.mfp-wellness-patient-intake .mfp-stepper-item[data-state="complete"] .mfp-step-label {
  color: var(--mf-accent-strong, #0b7d5e);
}

/* ============================================================
   PAGE / SECTION HEADS
   ============================================================ */
.mfp.mfp-wellness-patient-intake .mfp-page-head {
  margin-bottom: 20px;
}
.mfp.mfp-wellness-patient-intake .mfp-section-heading {
  font-size: 20px;
  font-weight: 700;
  letter-spacing: -0.01em;
  color: var(--mf-text, #17352b);
  margin-bottom: 6px;
}
.mfp.mfp-wellness-patient-intake .mfp-section-intro {
  font-size: 14px;
  line-height: 1.55;
  color: var(--mf-muted, #5c7a70);
}

/* ============================================================
   GRID
   ============================================================ */
.mfp.mfp-wellness-patient-intake .mfp-grid {
  display: grid;
  grid-template-columns: repeat(12, 1fr);
  gap: 18px;
}
.mfp.mfp-wellness-patient-intake .mfp-col-12 { grid-column: span 12; }
.mfp.mfp-wellness-patient-intake .mfp-col-6 { grid-column: span 6; }

/* ============================================================
   FIELD PRIMITIVES
   ============================================================ */
.mfp.mfp-wellness-patient-intake .mfp-field {
  display: flex;
  flex-direction: column;
  gap: 7px;
}
.mfp.mfp-wellness-patient-intake .mfp-label {
  font-size: 13px;
  font-weight: 600;
  color: var(--mf-text, #17352b);
}
.mfp.mfp-wellness-patient-intake .mfp-required {
  color: var(--mf-accent, #0f9d76);
  margin-left: 2px;
}
.mfp.mfp-wellness-patient-intake .mfp-hint {
  font-size: 12px;
  color: var(--mf-muted, #5c7a70);
}

/* Inputs, selects, textareas — pill / rounded */
.mfp.mfp-wellness-patient-intake .mfp-input,
.mfp.mfp-wellness-patient-intake .mfp-select,
.mfp.mfp-wellness-patient-intake .mfp-textarea {
  width: 100%;
  font: inherit;
  color: var(--mf-text, #17352b);
  background: var(--mf-surface, #ffffff);
  border: 1.5px solid var(--mf-border, rgba(15, 157, 118, 0.20));
  border-radius: var(--mf-input-radius, 14px);
  padding: 12px 16px;
  transition: border-color 0.2s ease, box-shadow 0.2s ease;
}
.mfp.mfp-wellness-patient-intake .mfp-input::placeholder,
.mfp.mfp-wellness-patient-intake .mfp-textarea::placeholder {
  color: var(--mf-placeholder, #9db5ac);
}
.mfp.mfp-wellness-patient-intake .mfp-textarea {
  border-radius: var(--mf-radius-sm, 16px);
  resize: vertical;
  min-height: 84px;
}
.mfp.mfp-wellness-patient-intake .mfp-input:focus,
.mfp.mfp-wellness-patient-intake .mfp-select:focus,
.mfp.mfp-wellness-patient-intake .mfp-textarea:focus {
  outline: none;
  border-color: var(--mf-accent, #0f9d76);
  box-shadow: 0 0 0 4px var(--mf-focus-ring, rgba(15, 157, 118, 0.16));
}

/* Radio / checkbox groups */
.mfp.mfp-wellness-patient-intake .mfp-options {
  display: flex;
  flex-direction: column;
  gap: 10px;
}
.mfp.mfp-wellness-patient-intake .mfp-option {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 12px 16px;
  border: 1.5px solid var(--mf-border, rgba(15, 157, 118, 0.20));
  border-radius: var(--mf-input-radius, 14px);
  background: var(--mf-surface, #ffffff);
  cursor: pointer;
  transition: border-color 0.2s ease, background 0.2s ease;
}
.mfp.mfp-wellness-patient-intake .mfp-option:hover {
  border-color: var(--mf-accent, #0f9d76);
  background: var(--mf-accent-soft, rgba(15, 157, 118, 0.06));
}
.mfp.mfp-wellness-patient-intake .mfp-option[data-selected="true"] {
  border-color: var(--mf-accent, #0f9d76);
  background: var(--mf-accent-soft, rgba(15, 157, 118, 0.10));
}
.mfp.mfp-wellness-patient-intake .mfp-option-mark {
  width: 20px;
  height: 20px;
  flex-shrink: 0;
  border: 2px solid var(--mf-border, rgba(15, 157, 118, 0.35));
  background: var(--mf-surface, #ffffff);
}
.mfp.mfp-wellness-patient-intake .mfp-option-mark.is-radio { border-radius: 50%; }
.mfp.mfp-wellness-patient-intake .mfp-option-mark.is-check { border-radius: 6px; }
.mfp.mfp-wellness-patient-intake .mfp-option[data-selected="true"] .mfp-option-mark {
  border-color: var(--mf-accent, #0f9d76);
  background: var(--mf-accent, #0f9d76);
  box-shadow: inset 0 0 0 3px var(--mf-surface, #ffffff);
}
.mfp.mfp-wellness-patient-intake .mfp-option-label {
  font-size: 14px;
  color: var(--mf-text, #17352b);
}

/* Consent rows */
.mfp.mfp-wellness-patient-intake .mfp-consent .mfp-option {
  align-items: flex-start;
}

/* Rating */
.mfp.mfp-wellness-patient-intake .mfp-rating {
  display: flex;
  gap: 8px;
}
.mfp.mfp-wellness-patient-intake .mfp-rating-dot {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  border: 1.5px solid var(--mf-border, rgba(15, 157, 118, 0.25));
  background: var(--mf-surface, #ffffff);
  color: var(--mf-muted, #5c7a70);
  font-weight: 700;
  font-size: 14px;
  cursor: pointer;
  transition: all 0.18s ease;
}
.mfp.mfp-wellness-patient-intake .mfp-rating-dot[data-selected="true"] {
  background: var(--mf-accent, #0f9d76);
  border-color: var(--mf-accent, #0f9d76);
  color: var(--mf-on-accent, #ffffff);
}

/* ============================================================
   ACTIONS
   ============================================================ */
.mfp.mfp-wellness-patient-intake .mfp-actions {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  margin-top: 32px;
  padding-top: 24px;
  border-top: 1px solid var(--mf-border, rgba(15, 157, 118, 0.12));
}
.mfp.mfp-wellness-patient-intake .mfp-btn {
  font: inherit;
  font-weight: 700;
  font-size: 14px;
  padding: 12px 26px;
  border-radius: 999px;
  cursor: pointer;
  border: 1.5px solid transparent;
  transition: transform 0.12s ease, background 0.2s ease, border-color 0.2s ease;
}
.mfp.mfp-wellness-patient-intake .mfp-btn:active { transform: translateY(1px); }
.mfp.mfp-wellness-patient-intake .mfp-btn-primary {
  background: var(--mf-accent, #0f9d76);
  color: var(--mf-on-accent, #ffffff);
}
.mfp.mfp-wellness-patient-intake .mfp-btn-primary:hover {
  background: var(--mf-accent-strong, #0b7d5e);
}
.mfp.mfp-wellness-patient-intake .mfp-btn-ghost {
  background: transparent;
  color: var(--mf-muted, #5c7a70);
  border-color: var(--mf-border, rgba(15, 157, 118, 0.25));
}
.mfp.mfp-wellness-patient-intake .mfp-btn-ghost:hover {
  color: var(--mf-text, #17352b);
  border-color: var(--mf-accent, #0f9d76);
}

/* ============================================================
   RESPONSIVE
   ============================================================ */
@media (max-width: 640px) {
  .mfp.mfp-wellness-patient-intake {
    padding: 28px 20px 24px;
    border-radius: var(--mf-radius-sm, 18px);
  }
  .mfp.mfp-wellness-patient-intake .mfp-col-6 { grid-column: span 12; }
  .mfp.mfp-wellness-patient-intake .mfp-step-label { display: none; }
  .mfp.mfp-wellness-patient-intake .mfp-form-title { font-size: 23px; }
}

/* MF-QA-PAGING-v2 */
.mfp.mfp-wellness-patient-intake .mfp-page{display:none!important;}
.mfp.mfp-wellness-patient-intake .mfp-page.is-active{display:block!important;}
